const PRODUCTS = [
  {
    name: "バタークリームマフィン",
    name_en: "Butter Cream Muffin",
    desc: "ふんわり軽い生地に、バターの香りが広がるマフィン。毎朝焼き立てをご用意しています。",
    price: "¥280",
    img: "data:image/jpeg;base64,"
  },
  {
    name: "チョコレートマドレーヌ",
    name_en: "Chocolate Madeleine",
    desc: "カカオたっぷりのマドレーヌ。しっとりとした食感と濃厚な風味をお楽しみください。",
    price: "¥220",
    img: "data:image/jpeg;base64,"
  },
  {
    name: "くまのマドレーヌ",
    name_en: "Bear Madeleine",
    desc: "くま型のキュートなマドレーヌ。プレーン・チョコの2種類。贈り物にも大人気です。",
    price: "¥280",
    img: "data:image/jpeg;base64,"
  }
];

// ---- Render products ----
function renderProducts() {
  const grid = document.getElementById('productsGrid');
  grid.innerHTML = PRODUCTS.map((p, i) => `
    <div class="product-card fade-up" style="animation-delay:${i * 0.12}s">
      <div class="product-img-wrap">
        <img src="${p.img}" alt="${p.name}" loading="lazy" />
      </div>
      <div class="product-body">
        <p class="product-en">${p.name_en}</p>
        <h3 class="product-name">${p.name}</h3>
        <p class="product-desc">${p.desc}</p>
        <p class="product-price">${p.price}</p>
        <a href="#order" class="btn-order">注文する</a>
      </div>
    </div>
  `).join('');
}

// ---- Scroll animations ----
function initObserver() {
  const io = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        io.unobserve(e.target);
      }
    });
  }, { threshold: 0.12 });
  document.querySelectorAll('.fade-up').forEach(el => io.observe(el));
}

// ---- Header scroll ----
function initHeader() {
  const header = document.getElementById('siteHeader');
  window.addEventListener('scroll', () => {
    header.classList.toggle('scrolled', window.scrollY > 40);
  });
}

// ---- Mobile nav ----
function initMobileNav() {
  const btn   = document.getElementById('navToggle');
  const close = document.getElementById('navClose');
  const nav   = document.getElementById('mainNav');
  if (!btn || !nav) return;
  btn.addEventListener('click', () => nav.classList.add('open'));
  if (close) close.addEventListener('click', () => nav.classList.remove('open'));
  nav.querySelectorAll('a').forEach(a => a.addEventListener('click', () => nav.classList.remove('open')));
}

// ---- Order form ----
function initForm() {
  const form = document.getElementById('orderForm');
  const msg  = document.getElementById('formMsg');
  if (!form) return;
  form.addEventListener('submit', e => {
    e.preventDefault();
    const name  = form.name.value.trim();
    const email = form.email.value.trim();
    if (!name || !email) {
      msg.textContent = 'お名前とメールアドレスをご入力ください。';
      return;
    }
    msg.textContent = 'ご注文ありがとうございます。確認メールをお送りします。';
    form.reset();
  });
}

// ---- Init ----
document.addEventListener('DOMContentLoaded', () => {
  renderProducts();
  initObserver();
  initHeader();
  initMobileNav();
  initForm();
  // Re-observe after products rendered
  setTimeout(initObserver, 100);
});
